import{C as t,o as n,c as l,a5 as s,E as r}from"./chunks/framework.CW28V7p_.js";const c=JSON.parse('{"title":"4. Upgrade safety patterns","description":"","frontmatter":{},"headers":[],"relativePath":"module-8/4-upgrade-safety.md","filePath":"module-8/4-upgrade-safety.md","lastUpdated":1780937944000}'),o={name:"module-8/4-upgrade-safety.md"},g=Object.assign(o,{setup(d){const e={id:"m8-4-upgrade",title:"🧠 Mini-check: Upgrade safety",intro:"2 питання.",questions:[{type:"order",q:"Safe upgrade procedure order:",items:["Backup keypairs до /tmp/","Build new version у versioned dir","Verify feature set unchanged (patch release)","Wait-for-restart-window","Swap symlink + systemctl restart","Verify post-restart (logs, monitor, slot delta, credits)"],correctOrder:[0,1,2,3,4,5],explanation:"Backup → build → verify → wait → swap → verify. Per cheatsheet §4. Module 8.4."},{type:"mcq",q:"Rollback triggers після upgrade?",options:["Panic/fatal у логах перші 5 хв","Credits не ростуть 2-3 хв після restart","Validator показує delinquent через 10 хв","Cluster halts"],correct:[0,1,2],explanation:"Cluster halt = NOT your fault, не rollback. Інші — твої problems. Module 8.4."}]};return(p,a)=>{const i=t("Quiz");return n(),l("div",null,[a[0]||(a[0]=s(`<h1 id="_4-upgrade-safety-patterns" tabindex="-1">4. Upgrade safety patterns <a class="header-anchor" href="#_4-upgrade-safety-patterns" aria-label="Permalink to &quot;4. Upgrade safety patterns&quot;">​</a></h1><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p>Safe upgrade = <strong>versioned dirs + symlink</strong> для instant rollback. Per cheatsheet §4 routine upgrade: backup → build → verify → wait-for-window → swap → verify → rollback if needed.</p><h2 id="key-principles" tabindex="-1">Key principles <a class="header-anchor" href="#key-principles" aria-label="Permalink to &quot;Key principles&quot;">​</a></h2><h3 id="versioned-dirs-symlink" tabindex="-1">Versioned dirs + symlink <a class="header-anchor" href="#versioned-dirs-symlink" aria-label="Permalink to &quot;Versioned dirs + symlink&quot;">​</a></h3><p>З cheatsheet:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/home/solana/ag-v0.4.0/   ← old version (preserved)</span></span>
<span class="line"><span>/home/solana/ag-v0.4.2/   ← new version (just built)</span></span>
<span class="line"><span>/home/solana/ag → ag-v0.4.2  (symlink, currently active)</span></span></code></pre></div><p>Switch version = <code>ln -sfn</code> (atomic). Rollback = same <code>ln -sfn</code> back. Old version preserved → instant rollback possible.</p><h3 id="six-phases-cheatsheet-§4" tabindex="-1">Six phases (cheatsheet §4) <a class="header-anchor" href="#six-phases-cheatsheet-§4" aria-label="Permalink to &quot;Six phases (cheatsheet §4)&quot;">​</a></h3><ol><li><strong>Pre-flight checks</strong>: cluster health, current version, baseline credits</li><li><strong>Build</strong>: новий version у versioned dir (з <code>cargo clean</code> для force fresh rebuild)</li><li><strong>Verify build produced new binary</strong>: timestamp recent + version matches expected</li><li><strong>Swap + restart</strong>: symlink → restart service</li><li><strong>Post-restart verify</strong>: live logs + monitor + slot delta + credits</li><li><strong>Rollback if needed</strong>: symlink back, restart</li></ol><h3 id="critical-build-pitfalls-з-2026-06-08-incident" tabindex="-1">Critical build pitfalls (з 2026-06-08 incident) <a class="header-anchor" href="#critical-build-pitfalls-з-2026-06-08-incident" aria-label="Permalink to &quot;Critical build pitfalls (з 2026-06-08 incident)&quot;">​</a></h3><p>Два subtle bugs які можуть skip detection і призвести до &quot;silent failure&quot;:</p><p><strong>Pitfall 1: Naïve sed на cargo-install-all.sh script</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># WRONG — duplicates --force on lines that already have it</span></span>
<span class="line"><span>sed -i &#39;s/install --locked/install --locked --force/g&#39; scripts/cargo-install-all.sh</span></span></code></pre></div><p>→ <code>cargo install --locked --force --force spl-token-cli</code> → error <code>--force used multiple times</code>.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># CORRECT — skip lines що вже мають --force</span></span>
<span class="line"><span>sed -i &#39;/--force/!s/install --locked/install --locked --force/g&#39; scripts/cargo-install-all.sh</span></span></code></pre></div><p><strong>Pitfall 2: Cargo cache silent skip</strong></p><p>Без <code>cargo clean</code> перед build, cargo може detect target/ artifacts up-to-date з previous build → skip compilation, output <code>Finished in 0.38s</code>. Binary НЕ updated to new version.</p><p>Symptom: build &quot;успішно&quot; завершується, але <code>agave-validator --version</code> все ще показує стару версію.</p><p>Fix: завжди <code>cargo clean</code> перед serious build (особливо upgrade):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cd /home/devops_ssh/agave</span></span>
<span class="line"><span>cargo clean</span></span>
<span class="line"><span># Тепер rebuild from scratch — ~25-30 хв</span></span></code></pre></div><p><strong>Завжди verify build output</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ls -la /home/devops_ssh/agave/bin/agave-validator    # date має бути recent</span></span>
<span class="line"><span>/home/devops_ssh/agave/bin/agave-validator --version  # version має бути нова</span></span></code></pre></div><p>Якщо date старе або version стара — НЕ proceed до Phase 4! Build did not produce new binary.</p><h3 id="pre-flight-checks-important" tabindex="-1">Pre-flight checks important <a class="header-anchor" href="#pre-flight-checks-important" aria-label="Permalink to &quot;Pre-flight checks important&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Cluster health (skip if delinquent &gt; 5%)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">solana</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> validators</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --url</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> localhost</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -E</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Active|Delinquent&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Baseline credits</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">solana</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vote-account</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> YOUR_VOTE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Credits</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Current version</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">agave-validator</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre></div><p>Якщо delinquent &gt; 5% — wait. Restart additional pressure може push cluster ближче до halt threshold.</p><h3 id="wait-for-restart-window" tabindex="-1">Wait-for-restart-window <a class="header-anchor" href="#wait-for-restart-window" aria-label="Permalink to &quot;Wait-for-restart-window&quot;">​</a></h3><p>Per cheatsheet §4 Phase 4:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> solana</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/solana/ag/bin/agave-validator</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --ledger</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/solana/solana/ledger</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    wait-for-restart-window</span></span></code></pre></div><p>Blocks until validator between leader slots (safe to restart без losing produced slots).</p><h3 id="verify-pattern-module-0-4-cheatsheet-§4-phase-5" tabindex="-1">Verify pattern (Module 0.4 + cheatsheet §4 Phase 5) <a class="header-anchor" href="#verify-pattern-module-0-4-cheatsheet-§4-phase-5" aria-label="Permalink to &quot;Verify pattern (Module 0.4 + cheatsheet §4 Phase 5)&quot;">​</a></h3><p>After restart:</p><ol><li><strong>Live logs</strong> — <code>sudo tail -f /home/solana/solana/solana.log</code>, watch 30-60s для panic/fatal</li><li><strong>Interactive monitor</strong> — <code>agave-validator monitor</code>, see Processed slot growing</li><li><strong>Slot delta</strong> — 10-15 slots / 5 sec = healthy</li><li><strong>Credits comparison</strong> — продовжує рости з baseline</li></ol><p>Не використовуй: <code>ps aux | grep</code>, <code>--version</code> (вже verified у Phase 3), post-mortem grep panic (слабше за live tail).</p><h3 id="rollback-triggers" tabindex="-1">Rollback triggers <a class="header-anchor" href="#rollback-triggers" aria-label="Permalink to &quot;Rollback triggers&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Indicator</th><th>Trigger?</th></tr></thead><tbody><tr><td>Panic/fatal у логах перші 5 хв</td><td>YES</td></tr><tr><td>Credits не ростуть 2-3 хв</td><td>YES</td></tr><tr><td>Validator показує delinquent через 10 хв</td><td>YES</td></tr><tr><td>Skip rate jump &gt; 5% над baseline</td><td>YES (after 1 epoch observation)</td></tr><tr><td>Cluster-wide issue</td><td>NO (не твоя проблема)</td></tr><tr><td>Тимчасовий network glitch</td><td>NO (wait, possibly recover)</td></tr></tbody></table><h3 id="rollback-command" tabindex="-1">Rollback command <a class="header-anchor" href="#rollback-command" aria-label="Permalink to &quot;Rollback command&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ln</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sfn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/solana/ag-v0.4.0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/solana/ag</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # symlink назад</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> solana</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Verify (same Phase 5)</span></span></code></pre></div><p>Old version directory must still exist (don&#39;t delete старі версії). Зазвичай keep last 2-3 versions, deleте старіші.</p><h2 id="connect-to-your-work" tabindex="-1">Connect to your work <a class="header-anchor" href="#connect-to-your-work" aria-label="Permalink to &quot;Connect to your work&quot;">​</a></h2><h3 id="coordination-upgrades" tabindex="-1">Coordination upgrades <a class="header-anchor" href="#coordination-upgrades" aria-label="Permalink to &quot;Coordination upgrades&quot;">​</a></h3><ul><li>Major version upgrades (mainnet): coordinated by Anza, social rollout. Check Discord/governance перед upgrading.</li><li>Patch releases: usually safe to upgrade anytime, but check release notes.</li><li>Bleeding edge (testnet, Alpenglow): cluster restarts and breaking changes common. Stay caught up.</li></ul><h3 id="document-upgrade-history" tabindex="-1">Document upgrade history <a class="header-anchor" href="#document-upgrade-history" aria-label="Permalink to &quot;Document upgrade history&quot;">​</a></h3><p>Personal log of:</p><ul><li>When upgraded which version</li><li>Issues encountered</li><li>Performance changes (skip rate before/after)</li></ul><p>Helps debug regressions, identify problematic versions.</p><h2 id="mini-quiz" tabindex="-1">Mini-quiz <a class="header-anchor" href="#mini-quiz" aria-label="Permalink to &quot;Mini-quiz&quot;">​</a></h2>`,48)),r(i,{data:e}),a[1]||(a[1]=s('<h2 id="glossary" tabindex="-1">Glossary <a class="header-anchor" href="#glossary" aria-label="Permalink to &quot;Glossary&quot;">​</a></h2><p><a href="/glossary#u"><code>Upgrade</code></a>, <a href="/glossary#r"><code>Rollback</code></a>, <a href="/glossary#s"><code>Symlink swap</code></a>, <a href="/glossary#w"><code>wait-for-restart-window</code></a></p><hr><p><strong>Попередньо:</strong> <a href="/module-8/3-monitoring">← 3. Monitoring</a> | <strong>Наступне:</strong> <a href="/module-8/final-quiz">⭐ Final quiz →</a></p>',4))])}}});export{c as __pageData,g as default};
